fn ed_teardown() -> i32 {
    /* ED_L_ID is arena-backed; bigint_drop_arena clears its slot before
     * arena_drop fires (called by each public entry point immediately before
     * arena_drop_call_helper).  Null the module var so any stale-handle read
     * returns BIGINT_INVALID. */
    bigint_drop(ED_L_ID)
    ED_L_ID = 0u64
    return 0i32
}

fn arena_drop_call_helper(id: u64) -> i32 {
    /* Honour bigint.iii:193-194: sweep all arena-backed bigint slots before
     * releasing the arena, making cleanup structural rather than dependent on
     * hand-counted per-handle drops.  Explicit bigint_drop calls in each
     * function become redundant (not load-bearing) after this sweep. */
    bigint_drop_arena(id)
    return arena_drop(id)
}
